 </div>

 <!-- CONTACT PANEL -->
 <div class="contact-scrim" id="contactScrim"></div>
 <aside class="contact-panel" id="contactPanel">
   <div class="flex items-center justify-between p-6 border-b border-white/5">
     <div><div class="font-display text-sm font-bold text-white uppercase tracking-wider">Inquiry</div><div class="text-[10px] text-stone mt-0.5 tracking-wide">We reply within 24 hours</div></div>
     <button class="nav-close" id="panelClose">&times;</button>
   </div>
   <form class="flex-1 overflow-y-auto p-6 space-y-4" onsubmit="event.preventDefault(); alert('Inquiry sent'); document.getElementById('contactPanel').classList.remove('open'); document.getElementById('contactScrim').classList.remove('open'); this.reset();">
     <div><label class="block text-[10px] tracking-[0.2em] uppercase text-stone mb-1.5">First name</label><input type="text" class="enq-field" placeholder="John" required></div>
     <div><label class="block text-[10px] tracking-[0.2em] uppercase text-stone mb-1.5">Last name</label><input type="text" class="enq-field" placeholder="Doe" required></div>
     <div><label class="block text-[10px] tracking-[0.2em] uppercase text-stone mb-1.5">Work email</label><input type="email" class="enq-field" placeholder="john@company.com" required></div>
     <div><label class="block text-[10px] tracking-[0.2em] uppercase text-stone mb-1.5">Company</label><input type="text" class="enq-field" placeholder="Acme Inc."></div>
     <div><label class="block text-[10px] tracking-[0.2em] uppercase text-stone mb-1.5">Message</label><textarea class="enq-field" rows="4" placeholder="Tell us about your goals..." required></textarea></div>
     <button type="submit" class="enq-submit rounded-full">Send inquiry &rarr;</button>
   </form>
   <div class="p-6 border-t border-white/5 text-[10px] tracking-wide text-stone/60 uppercase">Powered by BAZventures</div>
 </aside>

 <script>
   const panel = document.getElementById("contactPanel");
   const scrim = document.getElementById("contactScrim");
   function openPanel() { panel.classList.add("open"); scrim.classList.add("open"); }
   function closePanel() { panel.classList.remove("open"); scrim.classList.remove("open"); }
   document.querySelectorAll("[href='#contact']").forEach(a => { if (!a.closest(".contact-panel")) a.addEventListener("click", openPanel); });
   document.getElementById("panelClose").addEventListener("click", closePanel);
   scrim.addEventListener("click", closePanel);
   const observer = new IntersectionObserver((entries) => { entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add("visible"); observer.unobserve(e.target); } }); }, { threshold: 0.1 });
   document.querySelectorAll(".reveal").forEach(el => observer.observe(el));
   let last = 0;
   window.addEventListener("scroll", () => { const h = document.getElementById("siteHeader"); if (!h) return; const y = window.scrollY; if (y > 60) h.classList.add("is-solid"); else h.classList.remove("is-solid"); last = y; });
   document.querySelectorAll(".nav-link, .side-tab").forEach(a => a.addEventListener("click", (e) => { const id = a.getAttribute("href"); if (id && id.startsWith("#") && id.length > 1) { e.preventDefault(); const t = document.getElementById(id.slice(1)); if (t) t.scrollIntoView({ behavior: "smooth" }); } }));
 </script>
 </body>
 </html>
