.case-card h4 { font-family: var(--font-display); font-size: 1.0625rem; font-weight: 600; color: #fff; margin: .35rem 0 .5rem; text-transform: uppercase; }
.case-metric { font-family: var(--font-display); font-size: 1.5rem; font-weight: 700; color: var(--brand); line-height: 1.2; }
.case-result { font-size: .8rem; color: var(--stone); margin-top: .25rem; }
.case-duration { font-size: .7rem; color: var(--stone); opacity: .6; margin-top: .5rem; text-transform: uppercase; letter-spacing: .1em; }

/* Pillars */
.pillar { padding: 2.5rem 2rem; background: var(--panel); border: 1px solid rgba(255,255,255,.06); text-align: center; transition: all .3s var(--ease); }
