 .brand .mark{width:22px;height:22px;border:1.5px solid var(--fg);border-radius:5px;display:grid;place-items:center;font-size:12px}
 .nav-links{display:flex;gap:18px;font-size:13px;color:var(--muted);margin-left:8px}
 .nav-links a:hover{color:var(--fg)}
 .nav-right{margin-left:auto;display:flex;align-items:center;gap:12px}
 .search-btn{display:flex;align-items:center;gap:8px;border:1px solid var(--border);background:var(--bg-elev);
