 .search-btn kbd{font-family:var(--mono);background:var(--bg-2);padding:1px 6px;border-radius:4px;border:1px solid var(--border)}
 .theme-btn{width:36px;height:36px;border:1px solid var(--border);background:var(--bg-elev);border-radius:8px;cursor:pointer;font-size:15px}
