 .hero h1 .thin{font-weight:200;display:block;font-size:.42em;letter-spacing:.12em;color:var(--muted);margin-top:18px}
 .hero p{max-width:560px;margin:0 auto 36px;color:var(--muted);font-size:17px}
 .hero-cta{display:flex;gap:14px;justify-content:center;flex-wrap:wrap}
 .btn{font-family:var(--sans);font-size:14px;font-weight:600;padding:12px 24px;border-radius:10px;cursor:pointer;border:1px solid transparent;transition:.2s}
 .btn-primary{background:var(--fg);color:var(--bg)}
 .btn-primary:hover{opacity:.85}
 .btn-outline{border-color:var(--border-2);color:var(--fg);background:transparent}
 .btn-outline:hover{background:var(--hover)}
 .stats{display:flex;justify-content:center;gap:64px;margin-top:80px;flex-wrap:wrap}
 .stat .n{font-size:48px;font-weight:900;letter-spacing:-.04em}
 .stat .l{font-family:var(--mono);font-size:11px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase}
 .scroll-cue{margin-top:70px;font-family:var(--mono);font-size:11px;letter-spacing:.3em;color:var(--faint)}
 /* SECTIONS */
 section{padding:90px 0;border-top:1px solid var(--border)}
 .sec-num{font-family:var(--mono);font-size:13px;color:var(--faint);letter-spacing:.2em;margin-bottom:14px}
 .sec-title{font-size:clamp(30px,5vw,52px);font-weight:900;letter-spacing:-.04em;margin-bottom:10px}
 .sec-sub{color:var(--muted);max-width:600px;margin-bottom:50px;font-size:16px}
 .card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:28px}
 .grid{display:grid;gap:20px}
 .g2{grid-template-columns:repeat(2,1fr)}
 .g3{grid-template-columns:repeat(3,1fr)}
 .g4{grid-template-columns:repeat(4,1fr)}
 @media(max-width:820px){.g2,.g3,.g4{grid-template-columns:1fr}}
 .muted{color:var(--muted)} .faint{color:var(--faint)}
 .label{font-family:var(--mono);font-size:11px;letter-spacing:.18em;text-transform:uppercase;color:var(--muted)}

 /* GREY SCALES */
 .scale{display:flex;height:120px;border-radius:12px;overflow:hidden;border:1px solid var(--border)}
 .scale div{flex:1;cursor:pointer;transition:transform .15s;position:relative}
 .scale div:hover{transform:scaleY(1.08)}
 .scale-row{display:flex;gap:14px;align-items:center;margin:10px 0}
 .scale-row .line{height:14px;border-radius:3px;flex:1}
 .scale-row.warm{background:linear-gradient(90deg,#0a0a0a,#2a2622,#7d7873,#b8b2ab,#ffffff)}
 .scale-row.neutral{background:linear-gradient(90deg,#0a0a0a,#404040,#808080,#bfbfbf,#ffffff)}
 .scale-row.cool{background:linear-gradient(90deg,#0a0a0a,#222a2e,#73787d,#abb2b8,#ffffff)}
 .temp-chip{display:flex;align-items:center;gap:10px}
 .temp-chip .sw{width:34px;height:34px;border-radius:8px;border:1px solid var(--border)}
 .simul{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}
 .simul .box{aspect-ratio:1;border:1px solid var(--border);display:grid;place-items:center}
 .simul .inner{width:46%;height:46%;background:#555; border-radius:6px}
