 .mat{aspect-ratio:4/3;border-radius:12px;border:1px solid var(--border);display:grid;place-items:center;font-family:var(--mono);font-size:11px;letter-spacing:.2em;position:relative;overflow:hidden}
 .mat.concrete{background:#3a3a3a;background-image:radial-gradient(rgba(255,255,255,.08) 1px,transparent 1px);background-size:4px 4px}
 .mat.paper{background:#cfc9bf;color:#1a1a1a}
 .mat.smoke{background:linear-gradient(160deg,#6a6a6a,#2a2a2a)}
 .mat.metal{background:linear-gradient(120deg,#0a0a0a 0%,#8a8a8a 45%,#f0f0f0 50%,#8a8a8a 55%,#0a0a0a 100%)}
 .mat.glass{background:rgba(180,180,180,.15);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.25)}
 .mat.velvet{background:radial-gradient(circle at 50% 40%,#5a5a5a,#0a0a0a)}
 /* INSPECTOR */
 .inspector{border:1px solid var(--border);border-radius:14px;padding:22px;background:var(--bg-elev)}
 .swatch{height:90px;border-radius:10px;border:1px solid var(--border);margin-bottom:16px}
 .kv{display:flex;justify-content:space-between;font-size:13px;padding:5px 0;border-bottom:1px solid var(--border)}
 .kv:last-child{border:none}
 .kv .k{color:var(--muted)}
 /* TYPOGRAPHY */
 .type-show{font-weight:900;font-size:clamp(40px,8vw,96px);letter-spacing:-.06em;line-height:1}
 .weights{display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:18px}
 .wt{text-align:center}
 .wt .aa{font-size:40px;font-weight:900;line-height:1}
 .wt .wl{font-family:var(--mono);font-size:10px;color:var(--muted);letter-spacing:.1em;margin-top:6px}
 /* BUTTONS */
 .btn-demo{display:flex;gap:12px;flex-wrap:wrap;align-items:center}
 .btn-sec{background:var(--bg-elev);border:1px solid var(--border-2)}
 .btn-ghost{background:transparent;color:var(--muted)}
 .btn-ghost:hover{color:var(--fg)}
 .btn-link{background:transparent;color:var(--fg);text-decoration:underline;padding:12px 8px}
 .btn-icon{background:var(--fg);color:var(--bg);width:44px;height:44px;border-radius:10px;display:grid;place-items:center;font-size:18px}
 .btn-dis{opacity:.35;pointer-events:none}
 .btn-sm{padding:8px 16px;font-size:13px}
 .btn-lg{padding:16px 32px;font-size:15px}
 .btn-load{position:relative;color:transparent}
 .btn-load::after{content:"";position:absolute;width:16px;height:16px;border:2px solid var(--bg);border-top-color:transparent;border-radius:50%;animation:spin .7s linear infinite;top:50%;left:50%;transform:translate(-50%,-50%)}
 @keyframes spin{to{transform:translate(-50%,-50%) rotate(360deg)}}
