 .field{margin-bottom:16px}
 .field label{display:block;font-size:12px;color:var(--muted);margin-bottom:6px}
 .field input,.field select,.field textarea{width:100%;background:var(--bg-elev);border:1px solid var(--border-2);color:var(--fg);padding:10px 12px;border-radius:8px;font-family:var(--sans);font-size:14px}
