 .av:first-child{margin-left:0}
 .av.more{background:var(--fg);color:var(--bg)}
 /* TOOLTIP */
 .tip{position:relative;border:1px solid var(--border-2);padding:8px 14px;border-radius:8px;display:inline-block;font-size:13px;cursor:default}
 .tip:hover .tp{opacity:1;transform:translate(-50%,0)}
 .tp{position:absolute;left:50%;bottom:calc(100% + 8px);transform:translate(-50%,6px);background:var(--fg);color:var(--bg);font-size:11px;padding:5px 9px;border-radius:6px;white-space:nowrap;opacity:0;transition:.18s;pointer-events:none;font-weight:600}
 .tp.right{bottom:auto;left:calc(100% + 8px);top:50%;transform:translate(6px,-50%)}
 .tip:hover .tp.right{transform:translate(0,-50%)}
 /* PROGRESS / SKELETON */
 .bar{height:8px;background:var(--bg-2);border-radius:99px;overflow:hidden;margin:8px 0}
 .bar i{display:block;height:100%;background:var(--fg)}
 .skel{display:flex;flex-direction:column;gap:10px}
 .skel .ln{height:12px;background:var(--bg-2);border-radius:6px;animation:pulse 1.4s ease-in-out infinite}
 @keyframes pulse{0%,100%{opacity:.4}50%{opacity:1}}
 /* GLASS */
 .glass-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:12px}
 .gcard{aspect-ratio:1;border-radius:14px;border:1px solid var(--border);display:grid;place-items:center;font-family:var(--mono);font-size:10px;letter-spacing:.12em;text-align:center;padding:8px}
 .gcard.frosted{background:rgba(180,180,180,.12);backdrop-filter:blur(14px) saturate(1.4)}
 .gcard.smoked{background:rgba(20,20,20,.45);backdrop-filter:blur(10px) saturate(1.2)}
 .gcard.milk{background:rgba(245,245,245,.1)}
 .gcard.tinted{background:rgba(120,120,120,.18);backdrop-filter:blur(12px)}
