 .glass-ctrl{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:24px}
 .glass-ctrl label{font-size:11px;color:var(--muted);font-family:var(--mono);letter-spacing:.1em;text-transform:uppercase}
 .glass-ctrl .val{font-size:20px;font-weight:900;margin:4px 0}
 .glass-ctrl .sub{font-size:11px;color:var(--faint)}
+
+/* ACCORDION / TABS / NAV UI */
+.acc{border:1px solid var(--border);border-radius:12px;overflow:hidden}
+.acc-item{border-bottom:1px solid var(--border)}
+.acc-item:last-child{border:none}
+.acc-q{width:100%;text-align:left;background:var(--bg-elev);border:none;color:var(--fg);padding:16px 20px;font-size:15px;font-weight:600;cursor:pointer;display:flex;justify-content:space-between;align-items:center;font-family:var(--sans)}
+.acc-q .pm{font-family:var(--mono);color:var(--muted)}
+.acc-a{max-height:0;overflow:hidden;transition:max-height .3s ease;background:var(--card)}
+.acc-a p{padding:0 20px 18px;color:var(--muted);font-size:14px}
+.tabs{display:flex;gap:6px;border-bottom:1px solid var(--border);margin-bottom:18px}
+.tab{padding:10px 16px;font-size:14px;color:var(--muted);cursor:pointer;border-bottom:2px solid transparent;font-weight:600}
+.tab.active{color:var(--fg);border-bottom-color:var(--fg)}
+.tabpane{display:none;color:var(--muted);font-size:14px}
+.tabpane.active{display:block}
+.breadcrumb{font-size:13px;color:var(--muted)}
+.breadcrumb a:hover{color:var(--fg)}
+.breadcrumb .sep{margin:0 8px;color:var(--faint)}
+.pagination{display:flex;gap:6px}
+.pg{width:34px;height:34px;border:1px solid var(--border);border-radius:8px;display:grid;place-items:center;font-size:13px;cursor:pointer}
+.pg.active{background:var(--fg);color:var(--bg);border-color:var(--fg)}
+.pg.dots{border:none;cursor:default}
+.stepper{display:flex;align-items:center;gap:0}
+.step{display:flex;align-items:center;gap:10px}
+.step .dot{width:30px;height:30px;border-radius:50%;border:1px solid var(--border-2);display:grid;place-items:center;font-size:13px;font-weight:700}
+.step.done .dot{background:var(--fg);color:var(--bg);border-color:var(--fg)}
+.step.current .dot{border-color:var(--fg)}
+.step .ln{width:40px;height:1px;background:var(--border-2)}
+/* ALERTS */
+.alert{display:flex;gap:12px;align-items:flex-start;border:1px solid var(--border);border-radius:12px;padding:14px 16px;font-size:14px;margin-bottom:12px}
+.alert .ico{font-family:var(--mono);font-weight:700}
+.alert.info{background:var(--bg-elev)}
+.alert.success{border-color:var(--border-2)}
+.alert.warn{background:var(--bg-elev)}
+.alert.solid{background:var(--fg);color:var(--bg)}
+.alert .ttl{font-weight:700;display:block;margin-bottom:2px}
+.alert .msg{color:var(--muted)}
+.alert.solid .msg{color:var(--bg);opacity:.7}
+/* TOAST */
+.toast-wrap{position:fixed;bottom:24px;right:24px;z-index:200;display:flex;flex-direction:column;gap:10px}
+.toast{background:var(--glass);backdrop-filter:blur(20px);border:1px solid var(--border);border-radius:12px;padding:14px 18px;min-width:240px;font-size:14px;display:flex;gap:10px;align-items:center;box-shadow:var(--shadow);transform:translateX(120%);transition:transform .3s}
+.toast.show{transform:translateX(0)}
+.toast .dot{width:8px;height:8px;border-radius:50%;background:var(--fg)}
+.toast.err .dot{background:var(--fg)}
+/* STATS / DATA */
+.stat-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}
+.mini-stat{border:1px solid var(--border);border-radius:14px;padding:20px}
+.mini-stat .v{font-size:30px;font-weight:900;letter-spacing:-.03em}
+.mini-stat .l{font-size:12px;color:var(--muted)}
+.mini-stat .d{font-size:12px;color:var(--fg);font-family:var(--mono);margin-top:4px}
+.chart-card{border:1px solid var(--border);border-radius:16px;padding:24px}
+.bars{display:flex;align-items:flex-end;gap:8px;height:200px;margin-top:20px}
+.bars .col{flex:1;background:var(--bg-2);border-radius:6px 6px 0 0;position:relative;transition:height .6s}
+.bars .col:hover{background:var(--fg)}
+.bars .col span{position:absolute;bottom:100%;left:50%;transform:translateX(-50%);font-size:10px;font-family:var(--mono);color:var(--muted);margin-bottom:4px;opacity:0}
+.bars .col:hover span{opacity:1}
+.bars .col.cur{background:var(--fg)}
+.legend{display:flex;gap:18px;font-size:12px;color:var(--muted);margin-top:14px}
+.legend i{width:10px;height:10px;border-radius:3px;display:inline-block;margin-right:6px;vertical-align:middle}
+/* TABLE */
+table{width:100%;border-collapse:collapse;font-size:13px}
+th,td{text-align:left;padding:12px 10px;border-bottom:1px solid var(--border)}
+th{font-family:var(--mono);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--muted)}
+.status{font-size:11px;font-family:var(--mono);padding:3px 8px;border-radius:6px;background:var(--bg-2)}
+/* KANBAN */
+.kanban{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}
+@media(max-width:900px){.kanban{grid-template-columns:repeat(2,1fr)}}
+@media(max-width:560px){.kanban{grid-template-columns:1fr}}
+.kcol{background:var(--bg-elev);border:1px solid var(--border);border-radius:14px;padding:14px}
+.khead{display:flex;justify-content:space-between;align-items:center;font-size:12px;font-weight:700;font-family:var(--mono);letter-spacing:.08em;margin-bottom:12px;text-transform:uppercase}
+.khead .cnt{background:var(--bg-2);padding:1px 8px;border-radius:99px}
+.kcard{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:12px;margin-bottom:10px}
+.kcard .id{font-family:var(--mono);font-size:10px;color:var(--muted)}
+.kcard .tt{font-size:13px;margin:6px 0 10px;font-weight:600}
+.kcard .meta{display:flex;justify-content:space-between;align-items:center}
+.tag-pill{font-size:10px;font-family:var(--mono);padding:2px 7px;border:1px solid var(--border-2);border-radius:5px}
+.prog{height:5px;background:var(--bg-2);border-radius:99px;margin:8px 0;overflow:hidden}
+.prog i{display:block;height:100%;background:var(--fg)}

