 .hero .tag{font-family:var(--mono);font-size:12px;letter-spacing:.3em;color:var(--muted);margin-bottom:24px}
 .hero h1{font-size:clamp(48px,9vw,120px);font-weight:900;letter-spacing:-.06em;line-height:.95;margin-bottom:28px}
 .hero h1 .thin{font-weight:200;display:block;font-size:.42em;letter-spacing:.12em;color:var(--muted);margin-top:18px}
 .hero p{max-width:560px;margin:0 auto 36px;color:var(--muted);font-size:17px}
 .hero-cta{display:flex;gap:14px;justify-content:center;flex-wrap:wrap}
 .btn{font-family:var(--sans);font-size:14px;font-weight:600;padding:12px 24px;border-radius:10px;cursor:pointer;border:1px solid transparent;transition:.2s}
 .btn-primary{background:var(--fg);color:var(--bg)}
 .btn-primary:hover{opacity:.85}
 .btn-outline{border-color:var(--border-2);color:var(--fg);background:transparent}
 .btn-outline:hover{background:var(--hover)}
 .stats{display:flex;justify-content:center;gap:64px;margin-top:80px;flex-wrap:wrap}
 .stat .n{font-size:48px;font-weight:900;letter-spacing:-.04em}
 .stat .l{font-family:var(--mono);font-size:11px;letter-spacing:.2em;color:var(--muted);text-transform:uppercase}
 .scroll-cue{margin-top:70px;font-family:var(--mono);font-size:11px;letter-spacing:.3em;color:var(--faint)}
 /* SECTIONS */
 section{padding:90px 0;border-top:1px solid var(--border)}
 .sec-num{font-family:var(--mono);font-size:13px;color:var(--faint);letter-spacing:.2em;margin-bottom:14px}
 .sec-title{font-size:clamp(30px,5vw,52px);font-weight:900;letter-spacing:-.04em;margin-bottom:10px}
 .sec-sub{color:var(--muted);max-width:600px;margin-bottom:50px;font-size:16px}
 .card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:28px}
 .grid{display:grid;gap:20px}
 .g2{grid-template-columns:repeat(2,1fr)}
 .g3{grid-template-columns:repeat(3,1fr)}
 .g4{grid-template-columns:repeat(4,1fr)}
 @media(max-width:820px){.g2,.g3,.g4{grid-template-columns:1fr}}
 .muted{color:var(--muted)} .faint{color:var(--faint)}
 .label{font-family:var(--mono);font-size:11px;letter-spacing:.18em;text-transform:uppercase;color:var(--muted)}

 /* GREY SCALES */
 .scale{display:flex;height:120px;border-radius:12px;overflow:hidden;border:1px solid var(--border)}
 .scale div{flex:1;cursor:pointer;transition:transform .15s;position:relative}
 .scale div:hover{transform:scaleY(1.08)}
 .scale-row{display:flex;gap:14px;align-items:center;margin:10px 0}
 .scale-row .line{height:14px;border-radius:3px;flex:1}
 .scale-row.warm{background:linear-gradient(90deg,#0a0a0a,#2a2622,#7d7873,#b8b2ab,#ffffff)}
 .scale-row.neutral{background:linear-gradient(90deg,#0a0a0a,#404040,#808080,#bfbfbf,#ffffff)}
 .scale-row.cool{background:linear-gradient(90deg,#0a0a0a,#222a2e,#73787d,#abb2b8,#ffffff)}
 .temp-chip{display:flex;align-items:center;gap:10px}
 .temp-chip .sw{width:34px;height:34px;border-radius:8px;border:1px solid var(--border)}
 .simul{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}
 .simul .box{aspect-ratio:1;border:1px solid var(--border);display:grid;place-items:center}
 .simul .inner{width:46%;height:46%;background:#555; border-radius:6px}
 @media(max-width:680px){.simul{grid-template-columns:repeat(2,1fr)}}
 .material-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}
 .mat{aspect-ratio:4/3;border-radius:12px;border:1px solid var(--border);display:grid;place-items:center;font-family:var(--mono);font-size:11px;letter-spacing:.2em;position:relative;overflow:hidden}
 .mat.concrete{background:#3a3a3a;background-image:radial-gradient(rgba(255,255,255,.08) 1px,transparent 1px);background-size:4px 4px}
 .mat.paper{background:#cfc9bf;color:#1a1a1a}
 .mat.smoke{background:linear-gradient(160deg,#6a6a6a,#2a2a2a)}
 .mat.metal{background:linear-gradient(120deg,#0a0a0a 0%,#8a8a8a 45%,#f0f0f0 50%,#8a8a8a 55%,#0a0a0a 100%)}
 .mat.glass{background:rgba(180,180,180,.15);backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.25)}
 .mat.velvet{background:radial-gradient(circle at 50% 40%,#5a5a5a,#0a0a0a)}
 /* INSPECTOR */
 .inspector{border:1px solid var(--border);border-radius:14px;padding:22px;background:var(--bg-elev)}
 .swatch{height:90px;border-radius:10px;border:1px solid var(--border);margin-bottom:16px}
 .kv{display:flex;justify-content:space-between;font-size:13px;padding:5px 0;border-bottom:1px solid var(--border)}
 .kv:last-child{border:none}
 .kv .k{color:var(--muted)}
 /* TYPOGRAPHY */
 .type-show{font-weight:900;font-size:clamp(40px,8vw,96px);letter-spacing:-.06em;line-height:1}
 .weights{display:grid;grid-template-columns:repeat(auto-fill,minmax(120px,1fr));gap:18px}
 .wt{text-align:center}
 .wt .aa{font-size:40px;font-weight:900;line-height:1}
 .wt .wl{font-family:var(--mono);font-size:10px;color:var(--muted);letter-spacing:.1em;margin-top:6px}
 /* BUTTONS */
 .btn-demo{display:flex;gap:12px;flex-wrap:wrap;align-items:center}
 .btn-sec{background:var(--bg-elev);border:1px solid var(--border-2)}
 .btn-ghost{background:transparent;color:var(--muted)}
 .btn-ghost:hover{color:var(--fg)}
 .btn-link{background:transparent;color:var(--fg);text-decoration:underline;padding:12px 8px}
 .btn-icon{background:var(--fg);color:var(--bg);width:44px;height:44px;border-radius:10px;display:grid;place-items:center;font-size:18px}
 .btn-dis{opacity:.35;pointer-events:none}
 .btn-sm{padding:8px 16px;font-size:13px}
 .btn-lg{padding:16px 32px;font-size:15px}
 .btn-load{position:relative;color:transparent}
 .btn-load::after{content:"";position:absolute;width:16px;height:16px;border:2px solid var(--bg);border-top-color:transparent;border-radius:50%;animation:spin .7s linear infinite;top:50%;left:50%;transform:translate(-50%,-50%)}
 @keyframes spin{to{transform:translate(-50%,-50%) rotate(360deg)}}
 /* FORMS */
 .field{margin-bottom:16px}
 .field label{display:block;font-size:12px;color:var(--muted);margin-bottom:6px}
 .field input,.field select,.field textarea{width:100%;background:var(--bg-elev);border:1px solid var(--border-2);color:var(--fg);padding:10px 12px;border-radius:8px;font-family:var(--sans);font-size:14px}
 .field input:focus,.field select:focus,.field textarea:focus{outline:none;border-color:var(--fg)}
 .check{display:flex;align-items:center;gap:10px;font-size:14px;margin-bottom:10px}
 .check .box{width:18px;height:18px;border:1px solid var(--border-2);border-radius:5px;display:grid;place-items:center;font-size:12px}
 .range{width:100%;accent-color:var(--fg)}
 /* BADGES / AVATARS */
 .badge{display:inline-flex;align-items:center;gap:6px;font-size:12px;font-weight:600;padding:4px 10px;border-radius:7px}
 .b-solid{background:var(--fg);color:var(--bg)} .b-outline{border:1px solid var(--border-2)}
 .b-soft{background:var(--bg-2);color:var(--muted)} .b-mono{font-family:var(--mono);background:var(--bg-2)}
 .b-square{border-radius:0} .b-sharp{border-radius:3px}
 .b-dot::before{content:"";width:6px;height:6px;border-radius:50%;background:var(--fg)}
 .avatars{display:flex;align-items:center}
 .av{width:38px;height:38px;border-radius:50%;display:grid;place-items:center;font-size:13px;font-weight:700;border:2px solid var(--bg);margin-left:-10px;background:var(--bg-2)}
 .av:first-child{margin-left:0}
 .av.more{background:var(--fg);color:var(--bg)}
 /* TOOLTIP */
 .tip{position:relative;border:1px solid var(--border-2);padding:8px 14px;border-radius:8px;display:inline-block;font-size:13px;cursor:default}
 .tip:hover .tp{opacity:1;transform:translate(-50%,0)}
 .tp{position:absolute;left:50%;bottom:calc(100% + 8px);transform:translate(-50%,6px);background:var(--fg);color:var(--bg);font-size:11px;padding:5px 9px;border-radius:6px;white-space:nowrap;opacity:0;transition:.18s;pointer-events:none;font-weight:600}
 .tp.right{bottom:auto;left:calc(100% + 8px);top:50%;transform:translate(6px,-50%)}
 .tip:hover .tp.right{transform:translate(0,-50%)}
 /* PROGRESS / SKELETON */
 .bar{height:8px;background:var(--bg-2);border-radius:99px;overflow:hidden;margin:8px 0}
 .bar i{display:block;height:100%;background:var(--fg)}
 .skel{display:flex;flex-direction:column;gap:10px}
 .skel .ln{height:12px;background:var(--bg-2);border-radius:6px;animation:pulse 1.4s ease-in-out infinite}
 @keyframes pulse{0%,100%{opacity:.4}50%{opacity:1}}
 /* GLASS */
 .glass-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:12px}
 .gcard{aspect-ratio:1;border-radius:14px;border:1px solid var(--border);display:grid;place-items:center;font-family:var(--mono);font-size:10px;letter-spacing:.12em;text-align:center;padding:8px}
 .gcard.frosted{background:rgba(180,180,180,.12);backdrop-filter:blur(14px) saturate(1.4)}
 .gcard.smoked{background:rgba(20,20,20,.45);backdrop-filter:blur(10px) saturate(1.2)}
 .gcard.milk{background:rgba(245,245,245,.1)}
 .gcard.tinted{background:rgba(120,120,120,.18);backdrop-filter:blur(12px)}
 .gcard.mirror{background:linear-gradient(135deg,rgba(255,255,255,.25),rgba(255,255,255,.02));backdrop-filter:blur(8px)}
 .glass-ctrl{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:24px}
 .glass-ctrl label{font-size:11px;color:var(--muted);font-family:var(--mono);letter-spacing:.1em;text-transform:uppercase}
 .glass-ctrl .val{font-size:20px;font-weight:900;margin:4px 0}
 .glass-ctrl .sub{font-size:11px;color:var(--faint)}

 /* ACCORDION / TABS / NAV UI */
 .acc{border:1px solid var(--border);border-radius:12px;overflow:hidden}
 .acc-item{border-bottom:1px solid var(--border)}
 .acc-item:last-child{border:none}
 .acc-q{width:100%;text-align:left;background:var(--bg-elev);border:none;color:var(--fg);padding:16px 20px;font-size:15px;font-weight:600;cursor:pointer;display:flex;justify-content:space-between;align-items:center;font-family:var(--sans)}
 .acc-q .pm{font-family:var(--mono);color:var(--muted)}
 .acc-a{max-height:0;overflow:hidden;transition:max-height .3s ease;background:var(--card)}
 .acc-a p{padding:0 20px 18px;color:var(--muted);font-size:14px}
 .tabs{display:flex;gap:6px;border-bottom:1px solid var(--border);margin-bottom:18px}
 .tab{padding:10px 16px;font-size:14px;color:var(--muted);cursor:pointer;border-bottom:2px solid transparent;font-weight:600}
 .tab.active{color:var(--fg);border-bottom-color:var(--fg)}
 .tabpane{display:none;color:var(--muted);font-size:14px}
 .tabpane.active{display:block}
 .breadcrumb{font-size:13px;color:var(--muted)}
 .breadcrumb a:hover{color:var(--fg)}
 .breadcrumb .sep{margin:0 8px;color:var(--faint)}
 .pagination{display:flex;gap:6px}
 .pg{width:34px;height:34px;border:1px solid var(--border);border-radius:8px;display:grid;place-items:center;font-size:13px;cursor:pointer}
 .pg.active{background:var(--fg);color:var(--bg);border-color:var(--fg)}
 .pg.dots{border:none;cursor:default}
 .stepper{display:flex;align-items:center;gap:0}
 .step{display:flex;align-items:center;gap:10px}
 .step .dot{width:30px;height:30px;border-radius:50%;border:1px solid var(--border-2);display:grid;place-items:center;font-size:13px;font-weight:700}
 .step.done .dot{background:var(--fg);color:var(--bg);border-color:var(--fg)}
 .step.current .dot{border-color:var(--fg)}
 .step .ln{width:40px;height:1px;background:var(--border-2)}
 /* ALERTS */
 .alert{display:flex;gap:12px;align-items:flex-start;border:1px solid var(--border);border-radius:12px;padding:14px 16px;font-size:14px;margin-bottom:12px}
 .alert .ico{font-family:var(--mono);font-weight:700}
 .alert.info{background:var(--bg-elev)}
 .alert.success{border-color:var(--border-2)}
 .alert.warn{background:var(--bg-elev)}
 .alert.solid{background:var(--fg);color:var(--bg)}
 .alert .ttl{font-weight:700;display:block;margin-bottom:2px}
 .alert .msg{color:var(--muted)}
 .alert.solid .msg{color:var(--bg);opacity:.7}
 /* TOAST */
 .toast-wrap{position:fixed;bottom:24px;right:24px;z-index:200;display:flex;flex-direction:column;gap:10px}
 .toast{background:var(--glass);backdrop-filter:blur(20px);border:1px solid var(--border);border-radius:12px;padding:14px 18px;min-width:240px;font-size:14px;display:flex;gap:10px;align-items:center;box-shadow:var(--shadow);transform:translateX(120%);transition:transform .3s}
 .toast.show{transform:translateX(0)}
 .toast .dot{width:8px;height:8px;border-radius:50%;background:var(--fg)}
 .toast.err .dot{background:var(--fg)}
 /* STATS / DATA */
 .stat-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}
 .mini-stat{border:1px solid var(--border);border-radius:14px;padding:20px}
 .mini-stat .v{font-size:30px;font-weight:900;letter-spacing:-.03em}
 .mini-stat .l{font-size:12px;color:var(--muted)}
 .mini-stat .d{font-size:12px;color:var(--fg);font-family:var(--mono);margin-top:4px}
 .chart-card{border:1px solid var(--border);border-radius:16px;padding:24px}
 .bars{display:flex;align-items:flex-end;gap:8px;height:200px;margin-top:20px}
 .bars .col{flex:1;background:var(--bg-2);border-radius:6px 6px 0 0;position:relative;transition:height .6s}
 .bars .col:hover{background:var(--fg)}
 .bars .col span{position:absolute;bottom:100%;left:50%;transform:translateX(-50%);font-size:10px;font-family:var(--mono);color:var(--muted);margin-bottom:4px;opacity:0}
 .bars .col:hover span{opacity:1}
 .bars .col.cur{background:var(--fg)}
 .legend{display:flex;gap:18px;font-size:12px;color:var(--muted);margin-top:14px}
 .legend i{width:10px;height:10px;border-radius:3px;display:inline-block;margin-right:6px;vertical-align:middle}
 /* TABLE */
 table{width:100%;border-collapse:collapse;font-size:13px}
 th,td{text-align:left;padding:12px 10px;border-bottom:1px solid var(--border)}
 th{font-family:var(--mono);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--muted)}
 .status{font-size:11px;font-family:var(--mono);padding:3px 8px;border-radius:6px;background:var(--bg-2)}
 /* KANBAN */
 .kanban{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}
 @media(max-width:900px){.kanban{grid-template-columns:repeat(2,1fr)}}
 @media(max-width:560px){.kanban{grid-template-columns:1fr}}
 .kcol{background:var(--bg-elev);border:1px solid var(--border);border-radius:14px;padding:14px}
 .khead{display:flex;justify-content:space-between;align-items:center;font-size:12px;font-weight:700;font-family:var(--mono);letter-spacing:.08em;margin-bottom:12px;text-transform:uppercase}
 .khead .cnt{background:var(--bg-2);padding:1px 8px;border-radius:99px}
 .kcard{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:12px;margin-bottom:10px}
 .kcard .id{font-family:var(--mono);font-size:10px;color:var(--muted)}
 .kcard .tt{font-size:13px;margin:6px 0 10px;font-weight:600}
 .kcard .meta{display:flex;justify-content:space-between;align-items:center}
 .tag-pill{font-size:10px;font-family:var(--mono);padding:2px 7px;border:1px solid var(--border-2);border-radius:5px}
 .prog{height:5px;background:var(--bg-2);border-radius:99px;margin:8px 0;overflow:hidden}
 .prog i{display:block;height:100%;background:var(--fg)}

 /* OVERLAYS */
 .overlay{position:fixed;inset:0;background:rgba(0,0,0,.55);backdrop-filter:blur(6px);z-index:300;display:none;align-items:center;justify-content:center;padding:20px}
 .overlay.show{display:flex}
 .modal{background:var(--glass);backdrop-filter:blur(24px) saturate(1.4);border:1px solid var(--border);border-radius:18px;padding:28px;max-width:440px;width:100%;box-shadow:var(--shadow)}
 .modal h3{font-size:20px;font-weight:800;margin-bottom:8px}
 .modal p{color:var(--muted);font-size:14px;margin-bottom:20px}
 .modal .acts{display:flex;gap:10px;justify-content:flex-end}
 .drawer{position:fixed;top:0;right:0;height:100%;width:380px;max-width:90vw;background:var(--glass);backdrop-filter:blur(24px);border-left:1px solid var(--border);z-index:320;transform:translateX(100%);transition:transform .3s;padding:28px;overflow-y:auto}
 .drawer.show{transform:translateX(0)}
 .drawer h3{font-size:18px;font-weight:800;margin-bottom:18px}
 .close-x{position:absolute;top:18px;right:18px;width:32px;height:32px;border:1px solid var(--border);border-radius:8px;background:var(--bg-elev);cursor:pointer;font-size:15px}
 .menu{position:relative;display:inline-block}
 .menu-list{position:absolute;top:calc(100% + 6px);left:0;background:var(--glass);backdrop-filter:blur(20px);border:1px solid var(--border);border-radius:12px;padding:6px;min-width:180px;box-shadow:var(--shadow);display:none;z-index:50}
 .menu.open .menu-list{display:block}
 .menu-list button{width:100%;text-align:left;background:transparent;border:none;color:var(--fg);padding:9px 12px;border-radius:8px;font-size:13px;cursor:pointer;font-family:var(--sans);display:flex;justify-content:space-between}
 .menu-list button:hover{background:var(--hover)}
 .menu-list .sep{height:1px;background:var(--border);margin:5px 0}
 .pop{border:1px solid var(--border-2);padding:8px 14px;border-radius:8px;cursor:pointer;font-size:13px;background:var(--bg-elev);display:inline-block}
 .popover{position:relative;display:inline-block}
 .pop-content{position:absolute;top:calc(100% + 8px);left:0;width:280px;background:var(--glass);backdrop-filter:blur(20px);border:1px solid var(--border);border-radius:14px;padding:18px;box-shadow:var(--shadow);display:none;z-index:60}
 .popover.open .pop-content{display:block}
 /* NOTIFS / PROFILE */
 .notif{display:flex;gap:12px;padding:12px;border-bottom:1px solid var(--border)}
 .notif:last-child{border:none}
 .notif .t{font-size:11px;color:var(--faint);font-family:var(--mono)}
 .upload{border:1.5px dashed var(--border-2);border-radius:14px;padding:34px;text-align:center;color:var(--muted);font-size:14px}
 .file-row{display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid var(--border);font-size:13px}
 .file-row .sw{width:30px;height:36px;border:1px solid var(--border);border-radius:5px;background:var(--bg-2);display:grid;place-items:center;font-size:10px;font-family:var(--mono)}
 .file-row .meta{margin-left:auto;color:var(--faint);font-size:11px}
 .code-box{background:var(--bg);border:1px solid var(--border);border-radius:12px;padding:18px;font-family:var(--mono);font-size:12px;color:var(--muted);overflow-x:auto;line-height:1.7}
 .code-box .kw{color:var(--fg)}
 /* PRICING */
 .price-card{border:1px solid var(--border);border-radius:18px;padding:30px;position:relative;background:var(--card)}
 .price-card.popular{border-color:var(--fg)}
 .price-card .badge-pop{position:absolute;top:-12px;right:20px;background:var(--fg);color:var(--bg);font-size:10px;font-weight:700;font-family:var(--mono);padding:4px 10px;border-radius:99px;letter-spacing:.1em}
 .price-card .tier{font-size:13px;font-family:var(--mono);letter-spacing:.15em;text-transform:uppercase;color:var(--muted)}
 .price-card .amt{font-size:46px;font-weight:900;letter-spacing:-.03em;margin:10px 0}
 .price-card .desc{color:var(--muted);font-size:14px;min-height:42px}
 .price-card ul{list-style:none;margin:18px 0;font-size:14px}
 .price-card li{padding:7px 0;border-bottom:1px solid var(--border);display:flex;gap:10px}
 .price-card li::before{content:"—";color:var(--faint)}
 /* CHAT */
 .chat{border:1px solid var(--border);border-radius:16px;overflow:hidden}
 .chat-head{display:flex;align-items:center;gap:12px;padding:14px 18px;border-bottom:1px solid var(--border)}
 .chat-body{padding:18px;display:flex;flex-direction:column;gap:14px;min-height:240px}
 .msg{display:flex;gap:10px;max-width:80%}
 .msg .b{background:var(--bg-elev);padding:10px 14px;border-radius:12px;font-size:14px}
 .msg.me{margin-left:auto;flex-direction:row-reverse}
 .msg.me .b{background:var(--fg);color:var(--bg)}
 .chat-input{display:flex;gap:10px;padding:14px 18px;border-top:1px solid var(--border)}
 .chat-input input{flex:1;background:var(--bg-elev);border:1px solid var(--border-2);border-radius:10px;padding:10px 14px;color:var(--fg);font-family:var(--sans)}
 .chat-input input:focus{outline:none;border-color:var(--fg)}
 /* VIZ */
 .donut{width:160px;height:160px;border-radius:50%;display:grid;place-items:center;margin:0 auto;background:conic-gradient(var(--fg) 0 70%,var(--bg-2) 70% 100%)}
 .donut .hole{width:100px;height:100px;border-radius:50%;background:var(--card);display:grid;place-items:center;text-align:center}
 .gauge{width:160px;height:90px;overflow:hidden;position:relative;margin:0 auto}
 .gauge .arc{width:160px;height:160px;border-radius:50%;background:conic-gradient(var(--fg) 0 82%,var(--bg-2) 82% 100%);position:absolute;top:0;left:0;clip-path:polygon(0 0,100% 0,100% 50%,0 50%)}
 .gauge .gtxt{position:absolute;bottom:0;width:100%;text-align:center;font-size:22px;font-weight:900}
 .spark{display:flex;flex-direction:column;gap:6px;border:1px solid var(--border);border-radius:12px;padding:14px}
 .spark .sp{height:34px;width:100%}
 .heatmap{display:grid;grid-template-columns:repeat(13,1fr);gap:4px}
 .heatmap .h{aspect-ratio:1;border-radius:3px;background:var(--bg-2)}
 .heatmap .l{font-size:10px;color:var(--faint);display:grid;place-items:center;font-family:var(--mono)}
 /* STATES */
 .state-box{border:1px solid var(--border);border-radius:16px;padding:40px;text-align:center}
 .state-box .big{font-size:48px;font-weight:900}
 .state-box .stl{font-family:var(--mono);font-size:11px;letter-spacing:.2em;color:var(--muted);margin-bottom:16px}
 /* PROFILE */
 .profile{display:flex;gap:18px;align-items:center;flex-wrap:wrap}
 .profile .pav{width:72px;height:72px;border-radius:50%;background:var(--bg-2);display:grid;place-items:center;font-size:26px;font-weight:800;border:1px solid var(--border)}
 .pstats{display:flex;gap:32px;margin-top:18px;flex-wrap:wrap}
 .pstats .ps .n{font-size:26px;font-weight:900}
 .pstats .ps .l{font-size:11px;color:var(--muted);font-family:var(--mono)}
 .comment{display:flex;gap:12px;border-bottom:1px solid var(--border);padding:16px 0}
 .comment .b{font-size:14px}
 .comment .bn{font-weight:700;font-size:13px}
 .comment .ba{font-size:11px;color:var(--faint);font-family:var(--mono)}
 /* FOOTER */
 footer{border-top:1px solid var(--border);padding:60px 0 40px;margin-top:20px}
 .marquee{overflow:hidden;white-space:nowrap;border-top:1px solid var(--border);border-bottom:1px solid var(--border);padding:16px 0;font-family:var(--mono);font-size:12px;letter-spacing:.3em;color:var(--faint)}
 .foot-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr;gap:30px;margin:50px 0}
 .foot-col h4{font-family:var(--mono);font-size:11px;letter-spacing:.15em;text-transform:uppercase;color:var(--muted);margin-bottom:14px}
 .foot-col a{display:block;font-size:14px;color:var(--muted);padding:4px 0}
 .foot-col a:hover{color:var(--fg)}
 .foot-bot{display:flex;justify-content:space-between;font-size:12px;color:var(--faint);border-top:1px solid var(--border);padding-top:24px;flex-wrap:wrap;gap:10px}
 .status-dot{width:8px;height:8px;border-radius:50%;background:var(--fg);display:inline-block;margin-right:6px;animation:pulse 2s infinite}
 @media(max-width:680px){.foot-grid{grid-template-columns:1fr 1fr}.stat-grid{grid-template-columns:repeat(2,1fr)}.glass-grid{grid-template-columns:repeat(2,1fr)}.glass-ctrl{grid-template-columns:repeat(2,1fr)}.heatmap{grid-template-columns:repeat(8,1fr)}}
 /* UTIL */
 .flex{display:flex}.between{justify-content:space-between}.center{align-items:center}.gap10{gap:10px}.gap16{gap:16px}.gap20{gap:20px}.mt20{margin-top:20px}.mt30{margin-top:30px}.mt40{margin-top:40px}.mb20{margin-bottom:20px}.wfull{width:100%}
 </style>
